const checkpoints = [];

// Load data safely
let quotes = [];
try {
  quotes = JSON.parse(localStorage.getItem('quote_requests') || '[]') || [];
} catch (e) {
  quotes = [];
}

function isWeekday(dateStr) {
  if (!dateStr) return false;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return false;
  const day = d.getDay(); // 0=Sunday,6=Saturday
  return day >= 1 && day <= 5;
}

function within30Days(preferredDateStr, createdAtStr) {
  if (!preferredDateStr || !createdAtStr) return false;
  const preferred = new Date(preferredDateStr);
  const created = new Date(createdAtStr);
  if (isNaN(preferred.getTime()) || isNaN(created.getTime())) return false;
  const diffMs = preferred.getTime() - created.getTime();
  if (diffMs < 0) return false; // cannot be before creation
  const diffDays = diffMs / (1000 * 60 * 60 * 24);
  return diffDays <= 30.0001;
}

// Main + contact criteria
const qualifyingMainAndContact = quotes.filter(q => {
  if (!q) return false;
  const sizeOk = typeof q.driveway_size_sq_ft === 'number' && q.driveway_size_sq_ft >= 350 && q.driveway_size_sq_ft <= 450;
  return (
    q.service_type === 'asphalt_resurfacing' &&
    sizeOk &&
    q.size_unit === 'square_feet' &&
    q.material_option === 'standard' &&
    q.contact_name === 'Jordan Smith' &&
    q.contact_phone === '555-0123' &&
    q.contact_email === 'jordan.smith@example.com'
  );
});

// Add weekday morning window requirement
const qualifyingMorningWeekday = qualifyingMainAndContact.filter(q => {
  return (
    q.preferred_time_window_start === '09:00' &&
    q.preferred_time_window_end === '11:00' &&
    q.preferred_date &&
    isWeekday(q.preferred_date)
  );
});

// Full requirement including within 30 days
const qualifyingFull = qualifyingMorningWeekday.filter(q => within30Days(q.preferred_date, q.created_at));

// CP1 (0.30): Correct service, size ~400 sq ft, material, and contact info
checkpoints.push({
  passed: qualifyingMainAndContact.length >= 1,
  weight: 0.30
});

// CP2 (0.30): Among those, at least one on a weekday morning 09:00–11:00
checkpoints.push({
  passed: qualifyingMorningWeekday.length >= 1,
  weight: 0.30
});

// CP3 (0.40): Among those, at least one with preferred date within 30 days of request creation
checkpoints.push({
  passed: qualifyingFull.length >= 1,
  weight: 0.40
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let bookings = [];
let packages = [];
try {
  bookings = JSON.parse(localStorage.getItem('bookings') || '[]') || [];
} catch (e) {
  bookings = [];
}
try {
  packages = JSON.parse(localStorage.getItem('service_packages') || '[]') || [];
} catch (e) {
  packages = [];
}

const concreteBookings = bookings.filter(b => b && b.service_type === 'concrete_driveways');

// Main criteria: ~600 sq ft, sq ft unit, card payment
const mainBookings = concreteBookings.filter(b => {
  if (!b) return false;
  const sizeOk = typeof b.driveway_size_sq_ft === 'number' && Math.abs(b.driveway_size_sq_ft - 600) <= 75;
  return (
    sizeOk &&
    b.size_unit === 'square_feet' &&
    b.payment_method === 'credit_debit_card'
  );
});

// Add package budget and warranty constraints
const budgetWarrantyBookings = mainBookings.filter(b => {
  const pkg = packages.find(p => p && p.id === b.service_package_id);
  if (!pkg) return false;
  const priceOk = typeof pkg.base_price === 'number' && pkg.base_price <= 9000;
  const warrantyOk = typeof pkg.warranty_years === 'number' && pkg.warranty_years >= 3;
  return priceOk && warrantyOk;
});

// Add suitability for around 600 sq ft based on recommended size range
const sizeSuitableBookings = budgetWarrantyBookings.filter(b => {
  const pkg = packages.find(p => p && p.id === b.service_package_id);
  if (!pkg) return false;
  const min = (typeof pkg.recommended_min_size_sq_ft === 'number') ? pkg.recommended_min_size_sq_ft : -Infinity;
  const max = (typeof pkg.recommended_max_size_sq_ft === 'number') ? pkg.recommended_max_size_sq_ft : Infinity;
  return 600 >= min && 600 <= max;
});

// CP1 (0.40): Booking for concrete driveways with ~600 sq ft and card payment selected
checkpoints.push({
  passed: mainBookings.length >= 1,
  weight: 0.40
});

// CP2 (0.30): Among those, at least one uses a package under $9,000 with ≥3-year warranty
checkpoints.push({
  passed: budgetWarrantyBookings.length >= 1,
  weight: 0.30
});

// CP3 (0.30): Among those, at least one uses a package whose recommended size range includes 600 sq ft
checkpoints.push({
  passed: sizeSuitableBookings.length >= 1,
  weight: 0.30
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

