function isSaturdayAfternoon(dateStr, startTime) {
  if (!dateStr || !startTime) return false;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return false;
  const day = d.getDay(); // 6 = Saturday
  if (day !== 6) return false;
  // Treat afternoon as slots starting at or after 12:00 (e.g., 13:00, 15:00)
  return startTime >= '12:00';
}

// Find qualifying sealing packages (includes crack filling, ≥2-year warranty, supports 2-car)
const sealingPackages = packages.filter(p => {
  if (!p) return false;
  if (p.service_id !== 'driveway_sealing') return false;
  const warrantyOk = typeof p.warranty_years === 'number' && p.warranty_years >= 2;
  const crackOk = p.includes_crack_filling === true;
  const supportsTwoCar = Array.isArray(p.supported_driveway_categories) && p.supported_driveway_categories.includes('two_car');
  return warrantyOk && crackOk && supportsTwoCar;
});

let cheapestQualifyingPackage = null;
sealingPackages.forEach(p => {
  if (!p || typeof p.base_price !== 'number') return;
  if (!cheapestQualifyingPackage || p.base_price < cheapestQualifyingPackage.base_price) {
    cheapestQualifyingPackage = p;
  }
});

// Bookings for driveway sealing, 2-car, Saturday afternoon with the right contact
const mainBookings = bookings.filter(b => {
  if (!b) return false;
  return (
    b.service_type === 'driveway_sealing' &&
    b.driveway_category === 'two_car' &&
    isSaturdayAfternoon(b.scheduled_date, b.time_slot_start) &&
    b.contact_name === 'Morgan Lee' &&
    b.contact_phone === '555-0789' &&
    b.contact_email === 'morgan.lee@example.com'
  );
});

// Among those, ensure the package includes crack filling and ≥2-year warranty for 2-car driveways
const withQualifyingPackage = mainBookings.filter(b => {
  const pkg = packages.find(p => p && p.id === b.service_package_id);
  if (!pkg) return false;
  const inSet = sealingPackages.some(p => p.id === pkg.id);
  return inSet;
});

// Among those, ensure the cheapest qualifying package was selected
const withCheapestPackage = withQualifyingPackage.filter(b => {
  if (!cheapestQualifyingPackage) return false;
  return b.service_package_id === cheapestQualifyingPackage.id;
});

// CP1 (0.30): Booking for driveway sealing, 2-car driveway, scheduled on a Saturday afternoon with correct contact info
checkpoints.push({
  passed: mainBookings.length >= 1,
  weight: 0.30
});

// CP2 (0.30): Among those, at least one uses a sealing package that includes crack filling and ≥2-year warranty for 2-car driveways
checkpoints.push({
  passed: withQualifyingPackage.length >= 1,
  weight: 0.30
});

// CP3 (0.40): Among those, at least one uses the cheapest package that meets those criteria
checkpoints.push({
  passed: withCheapestPackage.length >= 1,
  weight: 0.40
});

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

