let favoriteRecords = [];
let projects = [];
try {
  favoriteRecords = JSON.parse(localStorage.getItem('favorite_projects') || '[]') || [];
} catch (e) {
  favoriteRecords = [];
}
try {
  projects = JSON.parse(localStorage.getItem('projects') || '[]') || [];
} catch (e) {
