}

const favRecord = favoriteRecords.find(r => r && r.id === 'default') || { project_ids: [] };
const favoriteIds = Array.isArray(favRecord.project_ids) ? favRecord.project_ids : [];

const now = new Date();
const twoYearsAgo = new Date(now.getTime());
twoYearsAgo.setFullYear(now.getFullYear() - 2);

const qualifyingFavoriteIds = favoriteIds.filter(id => {
  const p = projects.find(pr => pr && pr.id === id);
  if (!p) return false;
  if (p.surface_type !== 'asphalt') return false;
  if (typeof p.size_sq_ft !== 'number' || p.size_sq_ft < 400 || p.size_sq_ft > 800) return false;
  if (!p.completion_date) return false;
  const d = new Date(p.completion_date);
  if (isNaN(d.getTime())) return false;
  return d >= twoYearsAgo;
});

// CP1–3: Number of qualifying asphalt projects (400–800 sq ft, completed within last 2 years) that are favorited
[1, 2, 3].forEach((n, idx) => {
  const weights = [0.34, 0.33, 0.33];
  checkpoints.push({
    passed: qualifyingFavoriteIds.length >= n,
    weight: weights[idx]
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

