}

function findNearestServed(zipCode, zips) {
  const searchNum = parseInt(zipCode, 10);
  if (isNaN(searchNum)) return null;
  let nearest = null;
  let bestDiff = Infinity;
  zips.forEach(z => {
    if (!z || !z.is_served) return;
    const zNum = parseInt(z.zip_code, 10);
    if (isNaN(zNum)) return;
    const diff = Math.abs(zNum - searchNum);
    if (diff < bestDiff) {
      bestDiff = diff;
      nearest = z;
    }
  });
  return nearest;
}

const searchedZip = '30301';
const zipArea = zipAreas.find(z => z && z.zip_code === searchedZip) || null;
const nearestServed = findNearestServed(searchedZip, zipAreas);
let nearestServiceArea = null;
if (nearestServed) {
  nearestServiceArea = serviceAreas.find(s => s && s.id === nearestServed.service_area_id) ||
    serviceAreas.find(s => s && Array.isArray(s.covered_zip_codes) && s.covered_zip_codes.includes(nearestServed.zip_code)) || null;
}

const mainInquiries = inquiries.filter(i => {
  if (!i) return false;
  if (!nearestServed || !zipArea) return false;
  return (
    i.searched_zip_code === searchedZip &&
    i.nearest_served_zip_code === nearestServed.zip_code &&
    zipArea.is_served === false
  );
});

const messageInquiries = mainInquiries.filter(i => {
  if (!i || !i.message) return false;
  return (
    typeof i.message === 'string' &&
    i.message.includes(searchedZip) &&
    nearestServed && i.message.includes(nearestServed.zip_code)
  );
});

const contactInquiries = mainInquiries.filter(i => {
  if (!i || !nearestServiceArea) return false;
  return (
    i.name === 'Taylor Green' &&
    i.email === 'taylor.green@example.com' &&
    i.phone === '555-0990' &&
    i.service_area_id === nearestServiceArea.id
  );
});

// CP1 (0.40): Inquiry created for unserved 30301 with nearest served ZIP selected
checkpoints.push({
  passed: mainInquiries.length >= 1 && !!nearestServed && !!zipArea && zipArea.is_served === false,
  weight: 0.40
});

// CP2 (0.30): Inquiry message mentions both the original and nearest served ZIP codes
checkpoints.push({
  passed: messageInquiries.length >= 1,
  weight: 0.30
});

// CP3 (0.30): Inquiry includes correct contact info and links to the appropriate service area
checkpoints.push({
  passed: contactInquiries.length >= 1,
  weight: 0.30
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let promotions = [];
let bookings = [];
let packages = [];
try {
  promotions = JSON.parse(localStorage.getItem('promotions') || '[]') || [];
} catch (e) {
  promotions = [];
}
try {
