  bookings = [];
}
try {
  packages = JSON.parse(localStorage.getItem('service_packages') || '[]') || [];
} catch (e) {
  packages = [];
}

// Active percent promos with ≥15% and min project size requirement ≤ 500 sq ft
const qualifyingPromos = promotions.filter(p => {
  if (!p) return false;
  if (!p.is_active) return false;
  if (p.discount_type !== 'percent') return false;
  if (typeof p.discount_percent !== 'number' || p.discount_percent < 15) return false;
  const minSize = (typeof p.min_project_size_sq_ft === 'number') ? p.min_project_size_sq_ft : 0;
  return minSize <= 500;
});

function findPromoByCode(code) {
  if (!code) return null;
  const codeLower = String(code).trim().toLowerCase();
  return promotions.find(p => p && p.code && String(p.code).trim().toLowerCase() === codeLower) || null;
}

// Bookings where a qualifying promo is applied to a 550 sq ft project
const bookingsMain = bookings.filter(b => {
  if (!b || !b.applied_promo_code) return false;
  if (typeof b.driveway_size_sq_ft !== 'number' || b.driveway_size_sq_ft !== 550) return false;
  if (b.size_unit !== 'square_feet') return false;
  const promo = findPromoByCode(b.applied_promo_code);
  if (!promo) return false;
  const promoInSet = qualifyingPromos.some(p => p.id === promo.id);
  return promoInSet;
});

// Enforce service type eligibility and min project size constraints
const bookingsServiceAndSizeOk = bookingsMain.filter(b => {
  const promo = findPromoByCode(b.applied_promo_code);
  if (!promo) return false;
  if (Array.isArray(promo.eligible_service_types) && promo.eligible_service_types.length > 0) {
    if (!b.service_type || !promo.eligible_service_types.includes(b.service_type)) return false;
  }
  if (typeof promo.min_project_size_sq_ft === 'number') {
    if (typeof b.driveway_size_sq_ft !== 'number' || b.driveway_size_sq_ft < promo.min_project_size_sq_ft) return false;
  }
  return true;
});

// Ensure the discount is actually applied (total < subtotal and discount_amount > 0)
const bookingsWithDiscountApplied = bookingsServiceAndSizeOk.filter(b => {
  if (typeof b.subtotal_price !== 'number' || typeof b.total_price !== 'number') return false;
  if (typeof b.discount_amount !== 'number') return false;
  return b.discount_amount > 0 && b.total_price < b.subtotal_price;
});

// CP1 (0.30): Booking with 550 sq ft and an active ≥15% promo whose min size requirement ≤ 500 sq ft
checkpoints.push({
  passed: bookingsMain.length >= 1,
  weight: 0.30
});

// CP2 (0.30): Among those, promo is actually valid for the booking's service type and project size
checkpoints.push({
  passed: bookingsServiceAndSizeOk.length >= 1,
  weight: 0.30
});

// CP3 (0.40): Among those, discount is successfully applied on the booking summary (total < subtotal)
checkpoints.push({
  passed: bookingsWithDiscountApplied.length >= 1,
  weight: 0.40
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

