// Crews that qualify for asphalt driveway replacement with rating ≥4.5 and ≥5 reviews
const qualifyingCrews = crews.filter(c => {
  if (!c || !c.is_active) return false;
  const servesAsphaltReplacement = Array.isArray(c.service_types) && c.service_types.includes('asphalt_driveway_replacement');
  const ratingOk = typeof c.overall_rating === 'number' && c.overall_rating >= 4.5;
  const reviewsOk = typeof c.review_count === 'number' && c.review_count >= 5;
  return servesAsphaltReplacement && ratingOk && reviewsOk;
});

// Determine highest-rated crew among qualifying (rating desc, then review count desc)
let bestCrew = null;
if (qualifyingCrews.length > 0) {
  bestCrew = qualifyingCrews.slice().sort((a, b) => {
    if (b.overall_rating !== a.overall_rating) {
      return b.overall_rating - a.overall_rating;
    }
    return (b.review_count || 0) - (a.review_count || 0);
  })[0];
}

// Estimate requests made to that best crew for asphalt driveway replacement
const mainRequests = estimates.filter(r => {
  if (!r || !bestCrew) return false;
  return (
    r.crew_id === bestCrew.id &&
    r.service_type === 'asphalt_driveway_replacement'
  );
});

// Add size constraint (~650 sq ft) and unit
const sizeRequests = mainRequests.filter(r => {
  if (typeof r.driveway_size_sq_ft !== 'number') return false;
  const sizeOk = Math.abs(r.driveway_size_sq_ft - 650) <= 75;
  return sizeOk && r.size_unit === 'square_feet';
});

// Add correct contact info
const contactRequests = sizeRequests.filter(r => {
  return (
    r.contact_name === 'Riley Chen' &&
    r.contact_phone === '555-0345' &&
    r.contact_email === 'riley.chen@example.com'
  );
});

// CP1 (0.30): Estimate request submitted to the highest-rated qualifying asphalt replacement crew
