  passed: mainRequests.length >= 1 && !!bestCrew,
  weight: 0.30
});

// CP2 (0.30): Among those, at least one request is for ~650 sq ft with sq ft units
checkpoints.push({
  passed: sizeRequests.length >= 1,
  weight: 0.30
});

// CP3 (0.40): Among those, at least one request has the specified contact details
checkpoints.push({
  passed: contactRequests.length >= 1,
  weight: 0.40
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

